#include <tuple>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    vector<vector<tuple<long long, long long, long long>>> adj(n);
    for (auto& e : edges) {
        long long u = e[0], v = e[1], s = e[2], end = e[3];
        adj[u].push_back({v, s, end});
    }

    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;

    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    pq.push({0, 0});

    while (!pq.empty()) {
        auto [t, u] = pq.top();
        pq.pop();

        if (u == n - 1) return t;

        if (t > dist[u]) continue;

        for (auto& [v, s, e] : adj[u]) {
            long long earliest = max(t, s);
            if (earliest <= e) {
                long long next_t = earliest + 1;
                if (next_t < dist[v]) {
                    dist[v] = next_t;
                    pq.push({next_t, v});
                }
            }
        }

        long long next_t = t + 1;
        if (next_t < dist[u]) {
            dist[u] = next_t;
            pq.push({next_t, u});
        }
    }

    return -1;
}
